sql:
SELECT external_booklist_id, COUNT(*) AS total_books
FROM external_books
GROUP BY external_booklist_id;

SELECT MAX(requirement_value) AS max_books_required
FROM challenge_requirements
WHERE requirement_type = 'total_books';

SELECT badge_id, COUNT(*) AS badge_count
FROM student_badges
GROUP BY badge_id;

SELECT AVG(books_read) AS average_books_read
FROM student_challenges
WHERE status = 'completed';

SELECT SUM(books_read) AS total_books_read
FROM student_challenges
WHERE student_id = 1;

SELECT COUNT(DISTINCT student_id) AS total_students_completed_challenges
FROM student_challenges
WHERE status = 'completed';

SELECT challenge_level
FROM reading_challenges
WHERE status = 'active';

SELECT COUNT(*) 
FROM reading_challenges 
WHERE created_by = 0 AND status = 'active';

SELECT student_id, AVG(books_read) AS average_books_read
FROM student_challenges
GROUP BY student_id;

SELECT books_read, last_updated_at
FROM student_challenges
WHERE status = 'in progress';

SELECT COUNT(*) AS active_booklists
FROM booklists
WHERE status = 'active';

SELECT booklist_name
FROM booklists
WHERE status = 'active';

SELECT challenge_level, SUM(total_books_required) AS total_books_required
FROM reading_challenges
GROUP BY challenge_level;

SELECT COUNT(*) 
FROM student_badges 
WHERE badge_id = 1;
